// Fan out every decompressed file from every DOCX
// and carry over the parent DOCX metadata.

const out = [];

for (const [index, item] of $input.all().entries()) {
  const bins = item.binary || {};
  const meta = item.json || {};

  for (const [key, bin] of Object.entries(bins)) {
    const dir = (bin.directory || '').replace(/^[./]+/, '');
    const name = bin.fileName || '';
    const fullPath = (dir ? `${dir}/` : '') + name;

    out.push({
      json: {
        // preserve whatever Compression put here
        ...meta,

        // track which original DOCX this came from
        sourceIndex: index,
        sourceFileName:
          meta.filename || meta.fileName || bin.fileName || null,

        // per-file info inside the ZIP
        binKey: key,
        fileName: name,
        directory: dir,
        fullPath,
      },
      binary: {
        data: bin,
      },
    });
  }
}

return out;

const keep = [];

for (const item of $input.all()) {
  const p = (item.json.fullPath || '').toLowerCase();
  if (p.endsWith('word/document.xml')) {
    keep.push(item);   // return the whole item (json + binary) as-is
  }
}

if (!keep.length) {
  throw new Error('word/document.xml not found in DOCX archive');
}

return keep;

// Get XML string from the Extract From File node
const xml = $json.xml || $json.data || '';

// Basic XML → text conversion, preserving spacing
let text = xml
  .replace(/<w:p[^>]*>/g, '\n')      // paragraph tags → newline
  .replace(/<w:br[^>]*\/>/g, '\n')   // explicit breaks → newline
  .replace(/<[^>]+>/g, '')           // strip all remaining tags
  .replace(/&amp;/g, '&')
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>')
  .replace(/&quot;/g, '"')
  .replace(/&apos;/g, "'")
  .replace(/\s+\n/g, '\n')
  .replace(/\n{3,}/g, '\n\n')
  .trim();

const snippet = text.slice(0, 1200);

// Pull metadata back from Keep only word/document.xml
// This guarantees sourceFileName/filename survive even if Extract changed JSON.
const meta = $('Keep only word/document.xml').itemMatching($itemIndex).json || {};

return {
  json: {
    ...meta,        // filename, extension, directory, sourceFileName, etc.
    text,
    snippet
  },
  binary: $('Keep only word/document.xml').itemMatching($itemIndex).binary
};

// Ensure the Compression node recognizes this as a zip archive
const bin = { ...( $binary?.data ?? {} ) };

// If no fileName exists, invent one
const current = bin.fileName || 'doc.docx';
bin.fileName = current.replace(/\.docx$/i, '.zip');
bin.fileExtension = 'zip';        // important for Decompress quirks

return { json: { ...$json }, binary: { data: bin } };

