base.faieInputs = faieInputs;

const checklist = base.checklist || {};
base.checklist = checklist;

// Helper: ensure faieInputs.Research_Area_s is an array
if (!Array.isArray(faieInputs.Research_Area_s)) {
  if (faieInputs.Research_Area_s) {
    faieInputs.Research_Area_s = [faieInputs.Research_Area_s];
  } else {
    faieInputs.Research_Area_s = [];
  }
}

// 4. If we actually got any research areas, attach them
if (researchAreas.length) {
  faieInputs.Research_Area_s.push({
    sourceType: 'inferred_from_docs',
    title: 'Inferred Research Areas (DP0)',
    filename: null,
    snippet: researchAreas
      .map(r => r.label || '')
      .filter(Boolean)
      .join('; ')
      .slice(0, 400),
    text: JSON.stringify(researchAreas),
  });

  // Only mark as Inferred if not already Received
  if (checklist.Research_Area_s !== 'Received') {
    checklist.Research_Area_s = 'Inferred';
  }
}

// 5. Return a single merged DP0 item downstream
return [
  {
    json: base,
  },
];

