// Helper: treat empty / "N/A" / "none" as no content
function hasContent(value) {
  if (!value || typeof value !== 'string') return false;
  const trimmed = value.trim();
  if (!trimmed) return false;
  return !/^n\/?a$/i.test(trimmed) && !/^none$/i.test(trimmed);
}

// Helper: ensure faieInputs[key] is an array
function ensureArray(obj, key) {
  if (!obj[key]) {
    obj[key] = [];
  } else if (!Array.isArray(obj[key])) {
    obj[key] = [obj[key]];
  }
}

return items.map(item => {
  const json = item.json;

  // Ensure containers exist
  const faieInputs = json.faieInputs || {};
  const checklist  = json.checklist  || {};
  json.faieInputs  = faieInputs;
  json.checklist   = checklist;

  // Existing normalized form block (from Normalize Form Meta)
  const form = json.form || {};

  // Prefer values from form.*, then fall back to old top-level fields
  const nameRaw       = (form.name                       || json['Faculty Name'] || '').trim();
  const emailRaw      = (form.email                      || json['Email'] || '').trim();
  const websiteRaw    = (form.websiteRaw                 || json['Faculty Website'] || '').trim();
  const researchRaw   = (form.researchAreasRaw           || json['Research Area(s)'] || '').trim();
  const interestsRaw  = (form.interestsRaw               || json['Company Interests / Industry Verticals'] || '').trim();
  const goalsRaw      = (form.goalsRaw                   || json['Engagement goals'] || '').trim();

  // Write back a clean, canonical form block for downstream nodes
  json.form = {
    name:             nameRaw || null,
    email:            emailRaw || null,
    websiteRaw:       websiteRaw || null,
    researchAreasRaw: researchRaw || null,
    interestsRaw:     interestsRaw || null,
    goalsRaw:         goalsRaw || null,
  };

  // --- Research Areas from form ---
  if (hasContent(researchRaw)) {
    ensureArray(faieInputs, 'Research_Area_s');
    faieInputs.Research_Area_s.push({
      sourceType: 'form',
      title:      'Faculty-entered research areas (DP0)',
      filename:   null,
      snippet:    researchRaw.slice(0, 400),
      text:       researchRaw,
    });
    checklist.Research_Area_s = 'Received';
  }

  // --- Company Interests / Industry Verticals from form ---
  if (hasContent(interestsRaw)) {
    ensureArray(faieInputs, 'Industry_Verticals');
    faieInputs.Industry_Verticals.push({
      sourceType: 'form',
      title:      'Faculty-entered company interests / industry verticals (DP0)',
      filename:   null,
      snippet:    interestsRaw.slice(0, 400),
      text:       interestsRaw,
    });
    checklist.Industry_Verticals = 'Received';
  }

  // --- Engagement Goals from form ---
  if (hasContent(goalsRaw)) {
    ensureArray(faieInputs, 'Engagement_Goals');
    faieInputs.Engagement_Goals.push({
      sourceType: 'form',
      title:      'Faculty-entered engagement goals (DP0)',
      filename:   null,
      snippet:    goalsRaw.slice(0, 400),
      text:       goalsRaw,
    });
    checklist.Engagement_Goals = 'Received';
  }

  // No faculty/meta blocks anymore
  delete json.faculty;
  delete json.meta;

  item.json = json;
  return item;
});

// Combined DP.0 checklist + FAIE input bundle
// Assumes each incoming item has:
// - json.message.content.{ filename, label, confidence }
// - plus metadata from the extract pipeline: filename/title/sourceType/text/snippet

const ALL_LABELS = [
  'Research_Area_s',
  'Faculty_Bio',
  'Recent_Publications',
  'Faculty_Website',
  'Industry_Verticals',
  'Engagement_Goals',
];

// For upgrading status as stronger evidence appears
const statusOrder = { Pending: 0, Inferred: 1, Received: 2 };

// Initialise checklist and FAIE input buckets
const checklist = {};
const faieInputs = {};

for (const label of ALL_LABELS) {
  checklist[label] = 'Pending';
  faieInputs[label] = [];
}

const items = $input.all();

for (const { json } of items) {
  const msg = json.message || {};
  const content = msg.content || json.content || {};

  const label = content.label;
  let confidence = content.confidence;

  // Normalise confidence
  if (confidence === undefined || confidence === null) {
    confidence = 0;
  } else {
    confidence = Number(confidence);
    if (Number.isNaN(confidence)) confidence = 0;
  }

  if (!label) {
    // No label -> ignore for DP.0
    continue;
  }

  // Prefer classifier filename, then pipeline filename
  const filename =
    content.filename ??
    json.filename ??
    json.fileName ??
    json.sourceFileName ??
    null;

  const sourceType = json.sourceType ?? json.source_type ?? null;
  const title = json.title ?? json.Title ?? null;

  const fullText =
    typeof json.text === 'string'
      ? json.text
      : (json.data && typeof json.data.text === 'string'
          ? json.data.text
          : '');

  const snippet =
    typeof json.snippet === 'string'
      ? json.snippet
      : (typeof fullText === 'string' ? fullText.slice(0, 1200) : '');

  // Determine status from confidence
  const status =
    confidence >= 0.85 ? 'Received'
    : confidence >= 0.6 ? 'Inferred'
    : 'Pending';

  // Update checklist if the label is one of the DP.0 slots
  if (ALL_LABELS.includes(label)) {
    const current = checklist[label];
    if (statusOrder[status] > statusOrder[current]) {
      checklist[label] = status;
    }
  } else {
    // If you ever introduce extra labels, track them too
    if (!faieInputs[label]) faieInputs[label] = [];
  }

  // Always attach the document into the FAIE input bundle under its label
  faieInputs[label].push({
    filename,
    title,
    sourceType,
    confidence,
    snippet,
    text: fullText,
  });
}

// NOTE: no `pending` / `hasPending` – checklist is now the single source of truth
return [
  {
    json: {
      checklist,   // DP.0 status per input type
      faieInputs,  // Text + metadata grouped by input type
    },
  },
];

